# apt.map — logical name -> real Debian/Ubuntu package(s).
# Only rows where the name actually differs from the logical name (§1); anything
# not listed passes through unchanged.

build = build-essential
dev-headers = libssl-dev pkg-config
fd = fd-find

# lsd landed in Ubuntu repos in 23.04; jammy (22.04) has no native package, so
# install the official prebuilt .deb there (§1a facet row, G6). Every newer
# release + Debian keeps the native `lsd` and needs no row.
lsd@jammy = source:build_lsd_deb
